        return new Source("<!DOCTYPE html>
<html>
    <head>
        <meta charset=\"UTF-8\">
        <title>Locamon | {% block title %}{{controller_name}}{% endblock %}</title>
        {% block stylesheets %}
            <link rel=\"stylesheet\" href=\"{{ asset('styles/app.css') }}\">
        {% endblock %}
        {% block javascripts %}
            {% block importmap %}{{ importmap('app') }}{% endblock %}
        {% endblock %}
    </head>
    <body class=\"flex max-w-screen min-h-screen py-[3.5vh] box-border ml-[calc(8vw+0.7vw)]\"> <!-- ml navbar + margin-left -->
        {{ component('Navbar') }}
        <main class=\"flex flex-col h-auto w-full px-[10vw] box-border\"> <!-- min-h = 100vh - margin-navbar -->
            {# Flash messages #}
            <div class=\"container mx-auto px-4\">
                {% for label, messages in app.flashes %}
                    {% for message in messages %}
                        <div class=\"mb-4 px-4 py-3 rounded-lg {% if label == 'error' %}bg-red-100 text-red-800{% elseif label == 'success' %}bg-green-100 text-green-800{% else %}bg-gray-100 text-gray-800{% endif %}\">
                            {{ message }}
                        </div>
                    {% endfor %}
                {% endfor %}
            </div>

            {% block body %}
            {% endblock %}
        </main>
    </body>
</html>", "base.html.twig", "C:\\Users\\solla\\Documents\\GitHub\\2e-annee-UE2\\templates\\base.html.twig");
